namespace RobotFaceAssets {

const lv_image_dsc_t* GetEyeLeft(const char* emotion) {
    if (strcmp(emotion, "happy") == 0 || strcmp(emotion, "laughing") == 0) {
        return &eye_left_happy;
    } else if (strcmp(emotion, "sad") == 0 || strcmp(emotion, "crying") == 0) {
        return &eye_left_sad;
    } else if (strcmp(emotion, "thinking") == 0 || strcmp(emotion, "confused") == 0) {
        return &eye_left_think;
    } else if (strcmp(emotion, "sleepy") == 0 || strcmp(emotion, "relaxed") == 0) {
        return &eye_left_close;
    } else if (strcmp(emotion, "surprised") == 0 || strcmp(emotion, "shocked") == 0) {
        return &eye_left_big;
    } else if (strcmp(emotion, "loving") == 0 || strcmp(emotion, "shy") == 0) {
        return &eye_left_shy;
    } else if (strcmp(emotion, "winking") == 0) {
        return &eye_left_wink;
    } else if (strcmp(emotion, "big") == 0) {
        return &eye_left_big_big;
    }
    return &eye_left_normal;
}

const lv_image_dsc_t* GetEyeRight(const char* emotion) {
    if (strcmp(emotion, "happy") == 0 || strcmp(emotion, "laughing") == 0) {
        return &eye_right_happy;
    } else if (strcmp(emotion, "sad") == 0 || strcmp(emotion, "crying") == 0) {
        return &eye_right_sad;
    } else if (strcmp(emotion, "thinking") == 0 || strcmp(emotion, "confused") == 0) {
        return &eye_right_think;
    } else if (strcmp(emotion, "sleepy") == 0 || strcmp(emotion, "relaxed") == 0) {
        return &eye_right_close;
    } else if (strcmp(emotion, "surprised") == 0 || strcmp(emotion, "shocked") == 0) {
        return &eye_right_big;
    } else if (strcmp(emotion, "loving") == 0 || strcmp(emotion, "shy") == 0) {
        return &eye_right_shy;
    } else if (strcmp(emotion, "winking") == 0) {
        return &eye_right_wink;
    } else if (strcmp(emotion, "big") == 0) {
        return &eye_right_big_big;
    }
    return &eye_right_normal;
}

const lv_image_dsc_t* GetMouth(const char* emotion) {
    if (strcmp(emotion, "happy") == 0) {
        return &mouth_smile;
    } else if (strcmp(emotion, "laughing") == 0) {
        return &mouth_laugh;
    } else if (strcmp(emotion, "sad") == 0 || strcmp(emotion, "crying") == 0) {
        return &mouth_down;
    } else if (strcmp(emotion, "surprised") == 0 || strcmp(emotion, "shocked") == 0) {
        return &mouth_surprise;
    } else if (strcmp(emotion, "thinking") == 0 || strcmp(emotion, "confused") == 0) {
        return &mouth_o;
    } else if (strcmp(emotion, "relaxed") == 0) {
        return &mouth_relax;
    } else if (strcmp(emotion, "sleepy") == 0) {
        return &mouth_small_smile;
    }
    return &mouth_close;
}

const lv_image_dsc_t* GetBlush() {
    return &blush;
}

const lv_image_dsc_t* GetBackground() {
    return &bg;
}

void GetFaceImages(const char* emotion, RobotFaceImages& images) {
    images.eye_left = const_cast<lv_image_dsc_t*>(GetEyeLeft(emotion));
    images.eye_right = const_cast<lv_image_dsc_t*>(GetEyeRight(emotion));
    images.mouth = const_cast<lv_image_dsc_t*>(GetMouth(emotion));
    images.blush_left = const_cast<lv_image_dsc_t*>(GetBlush());
    images.blush_right = const_cast<lv_image_dsc_t*>(GetBlush());
}

}
